public class TicketService
{
    private readonly EventBookingContext _context;

    public TicketService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var @event = await _context.Events.FindAsync(eventId);
        if (@event == null || quantity <= 0 || quantity > @event.TotalSeats)
        {
            return false;
        }

        using (var transaction = await _context.Database.BeginTransactionAsync())
        {
            try
            {
                // Check available seats
                var reservedSeats = await _context.Events.Where(e => e.Id == eventId).SumAsync(e => e.ReservedSeats);
                if (reservedSeats + quantity > @event.TotalSeats)
                {
                    return false;
                }

                // Update inventory
                @event.ReservedSeats += quantity;
                await _context.SaveChangesAsync();

                // Commit transaction
                await transaction.CommitAsync();
                return true;
            }
            catch
            {
                await transaction.RollbackAsync();
                throw;
            }
        }
    }
